// HasUpstream applies the HasEdge predicate on the "upstream" edge.
func HasUpstream() predicate.MCPToolCall {
	return predicate.MCPToolCall(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, UpstreamTable, UpstreamColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUpstreamWith applies the HasEdge predicate on the "upstream" edge with a given conditions (other predicates).
func HasUpstreamWith(preds ...predicate.MCPUpstream) predicate.MCPToolCall {
	return predicate.MCPToolCall(func(s *sql.Selector) {
		step := newUpstreamStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasTool applies the HasEdge predicate on the "tool" edge.
func HasTool() predicate.MCPToolCall {
	return predicate.MCPToolCall(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, ToolTable, ToolColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasToolWith applies the HasEdge predicate on the "tool" edge with a given conditions (other predicates).
func HasToolWith(preds ...predicate.MCPTool) predicate.MCPToolCall {
	return predicate.MCPToolCall(func(s *sql.Selector) {
		step := newToolStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.MCPToolCall) predicate.MCPToolCall {
	return predicate.MCPToolCall(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.MCPToolCall) predicate.MCPToolCall {
	return predicate.MCPToolCall(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.MCPToolCall) predicate.MCPToolCall {
	return predicate.MCPToolCall(sql.NotPredicates(p))
}
